INSERT INTO profile_scenario_responses (id, profile_id, scenario_id, response, reasoning_chain, emotional_arc, confidence, generation_run_id) VALUES
('8f523f64-8e3f-4812-a950-aafebb2af151', 'fd1a475a-e7b5-4d05-b419-859d70b2195e', '710fa64f-7abc-4dbf-b354-9ace4f928b54', 'Faced with this, this profile lets the numbers set the floor and refuses to negotiate against itself, and true to form measures protocol loyalty by historical gas spent rather than current utility.', 'Distrusts the first plausible-sounding answer and keeps testing alternatives until one survives every objection raised against it. Every option here also has to survive the other side''s reaction.', 'The faintest tightening, gone as soon as it is noticed, resolving into euphoric overreach — that resolves almost before it registers.', 0.68, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('0c5f191a-9859-41f1-9095-7bb541e67e91', '6ca4867d-548b-43a8-98e7-16e70ab789db', '5ffd25ad-e2cf-4ead-a2c3-f4d4c93158ee', 'Faced with this, this type stays silent past the point of discomfort, letting the other side fill the gap, and true to form rewrites its own uncertainty out of the story after the fact.', 'Builds an explicit decision matrix for a call most people would make on instinct, and defers to whichever option scores highest even if it feels wrong. The relationship and the number are both on the table at once.', 'The faintest tightening, gone as soon as it is noticed, resolving into stoic freeze — that resolves almost before it registers.', 0.7, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('eedbc9a0-f668-4612-b63e-8b0eec0ff297', '65228199-23e8-4b0f-ad12-98569651a492', '2694f5ed-254b-4ac0-b2aa-9cce97933cad', 'Faced with this, the individual lets the numbers set the floor and refuses to negotiate against itself, and true to form underestimates how often an obviously right call turns out wrong.', 'Keeps expanding the list of scenarios to consider until diminishing returns finally force a stop. The relationship and the number are both on the table at once.', 'The faintest tightening, gone as soon as it is noticed, resolving into performative calm — that is essentially forgotten by the next decision.', 0.86, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('caf2d967-ac87-44d8-be09-67806205afb8', 'cf3308d5-02bd-43a7-9ac7-77d5b28d466f', '7b53045a-2a0f-4d68-a017-0b9964c1baaf', 'Faced with this, this person holds the line to their BATNA, trading patience for leverage and refusing to move first, and true to form refuses to exit positions until price returns to the previous cycle peak.', 'Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down. The counterparty is reading every hesitation as information.', 'Almost no visible reaction at all, resolving into cold calculation — that is essentially forgotten by the next decision.', 0.67, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('2136c80b-3547-4487-845c-4b8f18e9f45e', 'e525cd40-99e1-47e9-a849-32bc7e213ebf', 'cfa6ac84-bdab-4496-86fe-23ab7fd040cc', 'Faced with this, this person tracks concessions explicitly and matches them one-for-one, never more, and true to form treats past peak valuation as guaranteed future recovery.', 'Breaks the decision into weighted criteria before looking at gut feel, and lets the tally overrule any single strong reaction. The relationship and the number are both on the table at once.', 'The faintest tightening, gone as soon as it is noticed, resolving into stoic freeze — that never really rises to the level of a feeling at all.', 0.71, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('9f9e5c8c-8cba-4cf5-9c50-db349d58c5ca', 'cccf2ee3-1fbe-4b2e-aea3-bbdf01363e7e', '9ea7a7d2-962d-4ed9-a0fe-6e41ea61c5db', 'Faced with this, this type lets the numbers set the floor and refuses to negotiate against itself, and true to form sees malicious intent and exploit risk in every standard smart contract update.', 'Distrusts the first plausible-sounding answer and keeps testing alternatives until one survives every objection raised against it. The relationship and the number are both on the table at once.', 'A flash of heat that cools almost immediately, resolving into righteous anger — that settles once the choice is made.', 0.69, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('07525ab1-81f6-4207-9a58-0e26b6113971', '1ef53f9b-3b8f-4043-b9a8-9d6e7828d06d', '3e8e7fc6-7c0a-4595-a6d5-76c5de3f9a72', 'Faced with this, this profile lets the numbers set the floor and refuses to negotiate against itself, and true to form is surprised in the moment and certain in the retelling.', 'Revisits the same decision from a new angle each time doubt resurfaces, even after nominally deciding. The relationship and the number are both on the table at once.', 'The faintest tightening, gone as soon as it is noticed, resolving into cold calculation — that leaves no discernible trace once the moment passes.', 0.71, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('c862371e-083b-4e2a-b4a4-91c1ba80a6d3', '9fb45e7d-3a3b-46bf-8a6d-d912a6397dc9', 'a2944802-ded5-4860-9820-6b9c4517bde3', 'Faced with this, this person tracks concessions explicitly and matches them one-for-one, never more, and true to form underestimates how often an obviously right call turns out wrong.', 'Separates the emotional read from the analytical one on purpose, writes both down, and lets the analytical read win the tiebreak. Every option here also has to survive the other side''s reaction.', 'Something closer to mild interest than alarm, resolving into relief capitulation — that resolves almost before it registers.', 0.91, '4556417e-ac86-4549-833b-d3a75bd358ee'),
