('d731eae0-249f-49a6-ab00-372cd686c7c7', '8820b9e3-c057-4a5a-9ef0-026e71d2680e', 'b766f9b4-2dd2-4224-9863-4fb0c47dc325', 'Faced with this, this person stays silent past the point of discomfort, letting the other side fill the gap, and true to form holds their estimates with a certainty the track record does not support.', 'Keeps expanding the list of scenarios to consider until diminishing returns finally force a stop. The relationship and the number are both on the table at once.', 'Almost no visible reaction at all, resolving into performative calm — that leaves no discernible trace once the moment passes.', 0.86, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('28c18dd7-a43c-45e3-aec8-2423c8099407', 'd1153cba-7c54-4893-9af2-2612c664503e', '710fa64f-7abc-4dbf-b354-9ace4f928b54', 'Faced with this, the individual stays silent past the point of discomfort, letting the other side fill the gap, and true to form measures every later offer against the opening one, not against fair value.', 'Walks every branch and contingency in sequence, uneasy until the residual ambiguity is as small as it can be. The relationship and the number are both on the table at once.', 'Something closer to mild interest than alarm, resolving into euphoric overreach — that is essentially forgotten by the next decision.', 0.76, '4556417e-ac86-4549-833b-d3a75bd358ee')
INSERT INTO profile_scenario_responses (id, profile_id, scenario_id, response, reasoning_chain, emotional_arc, confidence, generation_run_id) VALUES
('639b1325-5fa2-4d6b-bff9-15411ee3d35c', '6f727962-38b0-423c-a631-befee828a247', '70f30104-9656-47f7-a3e3-2c38035c851c', 'Faced with this, this type lets the numbers set the floor and refuses to negotiate against itself, and true to form rewrites its own uncertainty out of the story after the fact.', 'Treats the choice as a small research problem: gather the knowable facts first, model the downside, then commit only once the math stops moving. The counterparty is reading every hesitation as information.', 'A flat, measured pulse with no real spike, resolving into relief capitulation — that is essentially forgotten by the next decision.', 0.73, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('8c7c0083-4bf6-4ff4-aa46-4a7fc262f97b', '4fbd654f-9c94-441b-a24e-9e15859c09fd', '424171e3-ca9f-4a67-8171-896465e1dec1', 'Faced with this, this person lets the numbers set the floor and refuses to negotiate against itself, and true to form expects to be the exception to a risk it can otherwise describe accurately.', 'Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down. The relationship and the number are both on the table at once.', 'Something closer to mild interest than alarm, resolving into stoic freeze — that leaves no discernible trace once the moment passes.', 0.7, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('98a10ed0-25a7-4868-88b5-888feabe7a2c', '95fef736-8142-41e3-90ba-f461dd2f3c96', '9ea7a7d2-962d-4ed9-a0fe-6e41ea61c5db', 'Faced with this, this type lets the numbers set the floor and refuses to negotiate against itself, and true to form extrapolates the last data point into a permanent trend.', 'Distrusts the first plausible-sounding answer and keeps testing alternatives until one survives every objection raised against it. The relationship and the number are both on the table at once.', 'The faintest tightening, gone as soon as it is noticed, resolving into cold calculation — that never really rises to the level of a feeling at all.', 0.66, '4556417e-ac86-4549-833b-d3a75bd358ee'),
('65c9107b-e341-444e-8d40-6bf204e1c6b1', '73957e4d-364a-443d-ac2f-55ee29df3d27', '207e7497-7bfb-4e9e-b53c-fbe2a062fd33', 'Faced with this, this person tracks concessions explicitly and matches them one-for-one, never more, and true to form is surprised in the moment and certain in the retelling.', 'Treats the choice as a small research problem: gather the knowable facts first, model the downside, then commit only once the math stops moving. The relationship and the number are both on the table at once.', 'A flat, measured pulse with no real spike, resolving into stoic freeze — that is essentially forgotten by the next decision.', 0.72, '4556417e-ac86-4549-833b-d3a75bd358ee'),
